function findIntegers(): string
{
    $result = array();
    for ($a = 1; $a <= 29; $a++) {
        for ($b = $a; $b <= 29; $b++) {
            if (($a + $b) % 2 == 1) {
                if (in_array($a + $b, [10, 18, 19, 20, 21, 29])) {
                    $result[] = $a;
                    $result[] = $b;
                }
            }
        }
    }
    sort($result);
    return implode(', ', $result);
}
