```php
function findIntegers(): string
{
    $result = array();
    for ($a = 1; $a <= 29; $a++) {
        for ($b = $a + 1; $b <= 29; $b++) {
            $sum = $a + $b;
            if (in_array($sum, array(10, 18, 19, 20, 21, 29))) {
                if ($sum == 10) {
                    $result[] = $a;
                    $result[] = 10 - $a;
                } elseif ($sum == 18) {
                    $result[] = $a;
                    $result[] = 18 - $a;
                } elseif ($sum == 19) {
                    $result[] = $a;
                    $result[] = 19 - $a;
                } elseif ($sum == 20) {
                    $result[] = $a;
                    $result[] = 20 - $a;
                } elseif ($sum == 21) {
                    $result[] = $a;
                    $result[] = 21 - $a;
                } else {
                    $result[] = $a;
                    $result[] = $sum - $a;
                }
            }
        }
    }
    sort($result);
    return implode(', ', $result);
}
