Here is the solution:

```plaintext
function findIntegers(): string {
    for (let a = 1; a <= 30; a++) {
        for (let b = a; b <= 30; b++) {
            let sum1 = a + b;
            for (let c = b; c <= 30; c++) {
                let sum2 = c + (a + b);
                for (let d = c; d <= 30; d++) {
                    let sum3 = d + (c + (a + b));
                    let sums = [sum1, sum2, sum3];
                    if (sums.every(x => [10, 18, 19, 20, 21, 29].includes(x))) {
                        return a + ", " + b + ", " + c + ", " + d;
                    }
                }
            }
        }
    }
    return "";
}
```

